mapper.select:
SELECT id, activity_id AS activityId, activity_name AS name, start_time AS startTime, end_time AS endTime, AS status, create_time AS createTime, update_time AS updateTime, create_by AS createBy, update_by AS updateBy, deleted FROM colonel_activity WHERE deleted = 0
AND = #{status}
ORDER BY start_time DESC NULLS LAST, create_time DESC NULLS LAST LIMIT #{limit} OFFSET #{offset}

SELECT id, activity_id AS activityId, activity_name AS name, start_time AS startTime, end_time AS endTime, AS status, create_time AS createTime, update_time AS updateTime, create_by AS createBy, update_by AS updateBy, deleted FROM colonel_activity WHERE deleted = 0
AND activity_name ILIKE CONCAT('%', #{activityName}, '%')
ORDER BY start_time DESC NULLS LAST, create_time DESC NULLS LAST LIMIT #{limit} OFFSET #{offset}

SELECT
FROM colonel_activity WHERE deleted = 0
ORDER BY assigned_at DESC NULLS LAST, last_sync_at DESC NULLS LAST, create_time DESC NULLS LAST LIMIT #{limit} OFFSET #{offset}

SELECT activity_id FROM colonel_activity WHERE deleted = 0 AND activity_id IS NOT NULL
AND (end_time IS NULL OR end_time >= CURRENT_TIMESTAMP) AND COALESCE(status, '') NOT IN ('已结束', '结束', 'CLOSED', 'ENDED', 'FINISHED', '0')
AND COALESCE(last_sync_at, update_time, create_time) >= #{recentSince}
AND activity_id IN
#{activityId}
ORDER BY last_sync_at DESC NULLS LAST, update_time DESC NULLS LAST, create_time DESC NULLS LAST LIMIT #{limit}

mapper.update:
UPDATE colonel_activity
SET last_sync_at = #{syncedAt},
    update_time = #{syncedAt}
WHERE deleted = 0
  AND activity_id = #{activityId}

UPDATE colonel_activity
SET activity_status_synced_at = #{syncedAt},
    update_time = #{syncedAt}
WHERE deleted = 0
  AND activity_id = #{activityId}
